public static String solve(long n) {
    long nSquared = n * n;
    long nCubed = n * n * n;

    String hexPart = Long.toHexString(nSquared).toUpperCase();

    StringBuilder base36Part = new StringBuilder();
    if (nCubed == 0) {
        base36Part.append("0");
    } else {
        long num = nCubed;
        while (num > 0) {
            int remainder = (int)(num % 36);
            if (remainder < 10) {
                base36Part.append(remainder);
            } else {
                base36Part.append((char)('A' + remainder - 10));
            }
            num = num / 36;
        }
    }
    base36Part.reverse();

    return hexPart + base36Part.toString();
}
